import{_ as e,o as i,c as s,ag as o}from"./chunks/framework.ByAj6Cie.js";const g=JSON.parse('{"title":"Categorías de Seguridad","description":"","frontmatter":{},"headers":[],"relativePath":"es/safety/categories.md","filePath":"es/safety/categories.md"}'),r={name:"es/safety/categories.md"};function d(l,a,n,c,t,p){return i(),s("div",null,[...a[0]||(a[0]=[o('<h1 id="categorias-de-seguridad" tabindex="-1">Categorías de Seguridad <a class="header-anchor" href="#categorias-de-seguridad" aria-label="Permalink to &quot;Categorías de Seguridad&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Las categorías de seguridad definen la estructura y la confiabilidad de los sistemas de control relacionados con la seguridad.</p><p>Describen cómo un sistema está diseñado para responder ante fallas y qué tan probable es que mantenga su función de seguridad.</p><p>Las categorías se utilizan para clasificar el desempeño de seguridad según principios de diseño y tolerancia a fallas.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de las categorías de seguridad es asegurar que los sistemas de seguridad proporcionen el nivel de protección requerido.</p><p>Se utilizan para:</p><ul><li>Definir la confiabilidad de las funciones de seguridad</li><li>Guiar el diseño del sistema</li><li>Apoyar las medidas de reducción de riesgos</li><li>Asegurar el cumplimiento de las normas de seguridad</li></ul><p>Ayudan a alinear el diseño del sistema con el nivel de riesgo.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Las categorías de seguridad se definen por cómo el sistema maneja las fallas y mantiene las funciones de seguridad.</p><h3 id="categoria-b" tabindex="-1">Categoría B <a class="header-anchor" href="#categoria-b" aria-label="Permalink to &quot;Categoría B&quot;">​</a></h3><p>Se aplican principios básicos de seguridad.</p><ul><li>Sin tolerancia específica a fallas</li><li>Una falla puede provocar la pérdida de la función de seguridad</li></ul><p>Se utiliza en aplicaciones de bajo riesgo.</p><h3 id="categoria-1" tabindex="-1">Categoría 1 <a class="header-anchor" href="#categoria-1" aria-label="Permalink to &quot;Categoría 1&quot;">​</a></h3><p>Utiliza componentes y principios bien probados.</p><ul><li>Mayor confiabilidad que el diseño básico</li><li>Aún sin detección de fallas</li></ul><p>Adecuada para riesgo bajo a moderado.</p><h3 id="categoria-2" tabindex="-1">Categoría 2 <a class="header-anchor" href="#categoria-2" aria-label="Permalink to &quot;Categoría 2&quot;">​</a></h3><p>Incluye pruebas periódicas de las funciones de seguridad.</p><ul><li>Las fallas pueden detectarse durante las pruebas</li><li>La función de seguridad puede perderse entre pruebas</li></ul><p>Proporciona mayor confiabilidad que la Categoría 1.</p><h3 id="categoria-3" tabindex="-1">Categoría 3 <a class="header-anchor" href="#categoria-3" aria-label="Permalink to &quot;Categoría 3&quot;">​</a></h3><p>Diseñada con redundancia.</p><ul><li>Una falla simple no provoca la pérdida de la función de seguridad</li><li>Algunas fallas pueden no detectarse</li></ul><p>Proporciona alta confiabilidad.</p><h3 id="categoria-4" tabindex="-1">Categoría 4 <a class="header-anchor" href="#categoria-4" aria-label="Permalink to &quot;Categoría 4&quot;">​</a></h3><p>Nivel más alto de confiabilidad.</p><ul><li>Las fallas se detectan continuamente</li><li>La función de seguridad se mantiene incluso con fallas</li></ul><p>Se utiliza en aplicaciones de alto riesgo.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las categorías de seguridad se utilizan en sistemas donde se requieren funciones de seguridad.</p><p>Las aplicaciones típicas incluyen:</p><ul><li>Sistemas de paro de emergencia</li><li>Enclavamientos de seguridad</li><li>Sistemas de protección de maquinaria</li><li>Sistemas de seguridad de proceso</li></ul><p>Son críticas en sistemas con peligros potenciales.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>La selección de categoría depende de la evaluación de riesgos.</p><p>Las categorías más altas aumentan la complejidad y el costo.</p><p>La detección de fallas y la redundancia mejoran el desempeño de seguridad.</p><p>El diseño del sistema debe seguir los principios definidos para cada categoría.</p><p>El cumplimiento de normas es obligatorio.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es seleccionar una categoría sin una evaluación de riesgos adecuada.</p><p>No asumir que una categoría más alta siempre es mejor. Debe coincidir con la aplicación.</p><p>Asegurar que todos los componentes cumplan la categoría requerida.</p><p>Verificar el desempeño del sistema mediante pruebas.</p><p>Documentar claramente el diseño de seguridad para validación y mantenimiento.</p>',49)])])}const m=e(r,[["render",d]]);export{g as __pageData,m as default};
